parameters.body/messageBody:
{
  "type": "AdaptiveCard",
  "$schema": "http://adaptivecards.io/schemas/adaptive-card.json",
  "version": "1.4",
  "body": [
    { "type": "TextBlock", "size": "Large", "weight": "Bolder", "text": "📝 New plan-update draft pending review" },
    { "type": "FactSet", "facts": [
      { "title": "Project", "value": "@{triggerBody()?['project_id']}" },
      { "title": "Draft", "value": "#@{triggerBody()?['draft_id']}" },
      { "title": "Items", "value": "@{triggerBody()?['items']}" },
      { "title": "Summary", "value": "@{triggerBody()?['summary']}" }
    ]}
  ],
  "actions": [
    { "type": "Action.OpenUrl", "title": "Review draft", "url": "@{parameters('PlannerBaseUrl')}/projects/@{triggerBody()?['project_id']}/drafts/@{triggerBody()?['draft_id']}" }
  ]
}

{
  "type": "AdaptiveCard",
  "$schema": "http://adaptivecards.io/schemas/adaptive-card.json",
  "version": "1.4",
  "body": [
    { "type": "TextBlock", "size": "Large", "weight": "Bolder", "color": "Good", "text": "✅ Plan update applied" },
    { "type": "FactSet", "facts": [
      { "title": "Project", "value": "@{triggerBody()?['project_id']}" },
      { "title": "Draft", "value": "#@{triggerBody()?['draft_id']}" },
      { "title": "Approved by", "value": "@{triggerBody()?['decided_by']}" },
      { "title": "Accepted / Rejected", "value": "@{triggerBody()?['accepted']} / @{triggerBody()?['rejected']}" }
    ]}
  ],
  "actions": [
    { "type": "Action.OpenUrl", "title": "Open Gantt", "url": "@{parameters('PlannerBaseUrl')}/projects/@{triggerBody()?['project_id']}/gantt" },
    { "type": "Action.OpenUrl", "title": "View change-log", "url": "@{parameters('PlannerBaseUrl')}/projects/@{triggerBody()?['project_id']}/changes" }
  ]
}
